css: /* Solution CSS for Toast Notification challenge */

   @tailwind base;

   @tailwind components;

   @tailwind utilities;

   .toast {

      display: none;

   }

   #toast-container {

      position: fixed;

      top: 10px;

      right: 10px;

   }
js: // Solution JavaScript for Toast Notification challenge

   const showToast = (title, message) => {

      const toastContainer = document.getElementById('toast-container');

      const toastTitle = document.getElementById('toast-title');

      const closeBtn = document.getElementById('close-btn');



      toastContainer.innerHTML = '';

      toastContainer.style.display = 'block';

      toastContainer.appendChild(document.createElement('div')).innerHTML = `<h1>${title}</h1><p>${message}</p>`;



      closeBtn.onclick = hideToast;

   }



   const hideToast = () => {

      const toastContainer = document.getElementById('toast-container');

      toastContainer.style.display = 'none';

   }



   document.addEventListener('DOMContentLoaded', () => {

      const showToastBtn = document.querySelector('.bg-green-500');

      showToastBtn.onclick = () => showToast('Hello, World!', 'This is a toast notification.');

   });
